                && event.properties.get("total_tokens") == Some(&json!(7))
                && event.properties.get("estimated_cost_usd") == Some(&json!("$0.0001"))
    ));
    assert!(matches!(
        &events[5],
        TelemetryEvent::SessionTrace(trace) if trace.name == "analytics"
    ));
}

