        ];

        // when
        let plan = BootstrapPlan::from_phases(phases);

        // then
        assert_eq!(
            plan.phases(),
            &[
                BootstrapPhase::CliEntry,
                BootstrapPhase::FastPathVersion,
                BootstrapPhase::MainRuntime,
            ]
        );
    }

    #[test]
    fn claude_code_default_covers_each_phase_once() {
        // given
        let expected = [
            BootstrapPhase::CliEntry,
